const raw = $input.item.json.text || $input.item.json.output || '';
const trigger = $('Execute Workflow Trigger').item.json;

// Extract JSON array from LLM response (handles markdown code blocks)
const start = raw.indexOf('[');
const end = raw.lastIndexOf(']');
if (start < 0 || end <= start) throw new Error('No JSON array found. Raw output: ' + raw.slice(0, 300));

let evals;
try {
  evals = JSON.parse(raw.slice(start, end + 1));
} catch (e) {
  throw new Error('JSON parse failed: ' + e.message + '\nRaw: ' + raw.slice(start, start + 300));
}

if (!Array.isArray(evals)) throw new Error('Expected a JSON array, got: ' + typeof evals);

// Validate required fields and deduplicate by character name
const seen = new Set();
evals = evals
  .filter(function(e) {
    if (!e.character || !e.chatMessage || !e.context || !e.thoughts) return false;
    const k = e.character.toLowerCase();
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  })
  .map(function(e, i) {
    return Object.assign({}, e, { id: i + 1 });
  });

if (evals.length < 5) throw new Error('Too few valid eval cases after filtering: ' + evals.length);

const filePath = 'agents/' + trigger.agent_folder + '/evals/eval-set.json';

return [{ json: {
  evals: evals,
  count: evals.length,
  fileContent: JSON.stringify(evals, null, 2),
  owner: trigger.owner,
  repo: trigger.repo,
  filePath: filePath
}}];

// Merge: if file exists pass its SHA for update, else create new file
const parsed = $('Parse and Validate').item.json;
const shaData = $input.item.json;

const body = {
  message: 'chore: update eval set for ' + (parsed.filePath.split('/')[1] || 'agent') + ' (' + parsed.count + ' cases)',
  content: Buffer.from(parsed.fileContent).toString('base64'),
  branch: 'main'
};

// SHA is required when updating an existing file
if (shaData && shaData.sha) {
  body.sha = shaData.sha;
}

return [{ json: {
  commitBody: JSON.stringify(body),
  owner: parsed.owner,
  repo: parsed.repo,
  filePath: parsed.filePath,
  count: parsed.count
}}];
